import { Component, OnInit, computed, signal } from '@angular/core';
import { CommonModule } from '@angular/common';
import { RouterLink } from '@angular/router';
import { ApiService } from '../../core/api.service';
import { CartItem } from '../../core/models';

/**
 * Storefront cart (`cart`, authGuard). Line items with qty stepper + remove and a
 * running total. service_agent wires ApiService.getCart()/updateCartItem()/removeCartItem().
 */
@Component({
  selector: 'app-cart',
  standalone: true,
  imports: [CommonModule, RouterLink],
  templateUrl: './cart.component.html',
  styleUrl: './cart.component.css',
})
export class CartComponent implements OnInit {
  readonly loading = signal(false);
  readonly error = signal<string | null>(null);

  // Mock cart lines — service_agent replaces with ApiService.getCart().items.
  readonly items = signal<CartItem[]>([
    {
      id: 'ci1',
      cartId: 'c1',
      productId: 'p1',
      qty: 1,
      product: {
        id: 'p1',
        name: 'Aurora Wireless Headphones',
        description: 'Over-ear noise-cancelling headphones.',
        priceCents: 18900,
        imageUrl: 'https://images.unsplash.com/photo-1505740420928-5e560c06d30e?w=300&q=80',
        stockQty: 24,
      },
    },
    {
      id: 'ci2',
      cartId: 'c1',
      productId: 'p2',
      qty: 2,
      product: {
        id: 'p2',
        name: 'Terra Insulated Bottle',
        description: 'Double-walled stainless steel bottle.',
        priceCents: 3200,
        imageUrl: 'https://images.unsplash.com/photo-1602143407151-7111542de6e8?w=300&q=80',
        stockQty: 120,
      },
    },
  ]);

  readonly totalCents = computed(() =>
    this.items().reduce((sum, i) => sum + (i.product?.priceCents ?? 0) * i.qty, 0),
  );
  readonly itemCount = computed(() => this.items().reduce((sum, i) => sum + i.qty, 0));

  constructor(private api: ApiService) {}

  ngOnInit(): void {
    this.loading.set(true);
    this.error.set(null);
    this.api.getCart().subscribe({
      next: (cart) => {
        this.items.set(cart.items ?? []);
        this.loading.set(false);
      },
      error: () => {
        this.error.set('Could not load your cart.');
        this.loading.set(false);
      },
    });
  }

  lineTotal(item: CartItem): number {
    return (item.product?.priceCents ?? 0) * item.qty;
  }

  inc(item: CartItem): void {
    this.setQty(item, item.qty + 1);
  }
  dec(item: CartItem): void {
    if (item.qty <= 1) {
      this.remove(item);
      return;
    }
    this.setQty(item, item.qty - 1);
  }

  private setQty(item: CartItem, qty: number): void {
    // Optimistic local update so the mockup is interactive.
    this.items.update((list) =>
      list.map((i) => (i.productId === item.productId ? { ...i, qty } : i)),
    );
    this.api.updateCartItem(item.productId, qty).subscribe({ error: () => {} });
  }

  remove(item: CartItem): void {
    this.items.update((list) => list.filter((i) => i.productId !== item.productId));
    this.api.removeCartItem(item.productId).subscribe({ error: () => {} });
  }

  money(cents: number): string {
    return '$' + (cents / 100).toFixed(2);
  }
}
